-- BuzzRecs — Date Night SEED (Chicago recognized restaurants & bars).
-- Run AFTER 2026-07-20-date-nights.sql, via the dashboard SQL editor.
-- Idempotent + safe: new venues insert into `places` only if a place of the
-- same name doesn't already exist (existing venues like Gilt Bar / Gus' Sip &
-- Dip are matched by name, never duplicated); each date_nights row attaches by
-- name. Re-running changes nothing.
-- Sources: MICHELIN Guide Chicago 2025 (stars + Bib Gourmand), NYT Best of
-- Chicago, North America's 50 Best Bars 2026.

create temporary table dn_seed (
  name text, slug text, neighborhood text, address text, website_url text,
  reservation_url text, description text, michelin_stars int, bib_gourmand boolean,
  fifty_best text, nyt boolean, cuisine text, price text, reservation_platform text
) on commit drop;


-- 1) insert brand-new venues (skip anything already on the site, by name)
select s.name, s.slug, s.neighborhood, s.address, s.website_url, s.reservation_url, s.description, 'approved', true
from dn_seed s
where not exists (select 1 from places p where lower(p.name) = lower(s.name))
on conflict (slug) do nothing;

-- 2) flag existing venues that are also date-night spots
update places p set is_date_night = true
from dn_seed s where lower(p.name) = lower(s.name);

-- 3) attach the date_nights accolade row to each place (by name)
select p.id, s.michelin_stars, s.bib_gourmand, s.fifty_best, s.nyt, s.cuisine, s.price, s.reservation_platform, s.description, now()
from places p
join dn_seed s on lower(p.name) = lower(s.name)
on conflict (place_id) do nothing;
